#!/usr/bin/env node

// Bundle the server into a single JS file for Node SEA.
// Inlines ALL dependencies (including express) so SEA is self-contained.
// Output: dist/server-bundle.js

import path from "node:path";
import { fileURLToPath } from "node:url";
import { build } from "esbuild";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const root = path.resolve(__dirname, "..");

await build({
	entryPoints: [path.join(root, "packages/server/src/index.js")],
	bundle: true,
	platform: "node",
	target: "node18",
	format: "esm",
	outfile: path.join(root, "dist/server-bundle.js"),
	// No externals — SEA must be fully self-contained.
	// Banner injects a real require() so express's dynamic requires work in ESM.
	banner: {
		js: [
			"// Claudia server bundle — generated by scripts/bundle-server.js",
			"// Do not edit directly.",
			"import { createRequire as __createRequire } from 'node:module';",
			"const require = __createRequire(import.meta.url);",
			"",
		].join("\n"),
	},
	sourcemap: false,
	minify: false,
	treeShaking: true,
});

console.log("Server bundled to dist/server-bundle.js");
